CREATE TABLE `Dataset` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(400) NOT NULL,
  `publisher` varchar(150) DEFAULT NULL,
  `license` varchar(100) DEFAULT NULL,
  `harvestSourceTitle` varchar(100) DEFAULT NULL,
  `description` text,
  `programCode` varchar(100) DEFAULT NULL,
  `lastModificationDate` date DEFAULT NULL,
  `identifier` varchar(150) DEFAULT NULL,
  `accessLevel` enum('public','non-public','restricted public') DEFAULT NULL,
  `createDate` date DEFAULT NULL,
  `bureauCode` varchar(50) DEFAULT NULL,
  `orgName` varchar(150) DEFAULT NULL,
  `maintainerEmail` varchar(100) DEFAULT NULL,
  `topicName` varchar(50) DEFAULT NULL,
--
CREATE TABLE `DatasetTags` (
  `datasetId` int NOT NULL,
  `tag` varchar(150) NOT NULL,
  PRIMARY KEY (`datasetId`,`tag`),
